// Hierarchical Bayesian model for binomial data
// Reparameterized for better mixing
// Prior: p(alpha, beta) proportional to (alpha + beta)^(-5/2)

transformed data {
  real eta_min = -10;
}

parameters {
  real<lower=0, upper=1> phi;           // phi = alpha/(alpha+beta)
  real eta;                              // eta = log(alpha + beta)
  array[N] real<lower=0, upper=1> theta; // group probabilities
}

model {
  // Compute alpha and beta from reparameterization
  real K = exp(eta);
  real alpha = phi * K;
  real beta = (1 - phi) * K;

  // Prior in (phi, eta) space:
  // p(alpha,beta) = (alpha+beta)^{-5/2}
  // Jacobian from (alpha,beta) to (phi,K) is K
  // Jacobian from K to eta is exp(eta) = K
